import{_ as t,o,c as r,ag as d}from"./chunks/framework.CTpQozEL.js";const x=JSON.parse('{"title":"Perplexity","description":"Perplexity 웹 검색 프로바이더 설정 (API 키, 검색 모드, 필터링)","frontmatter":{"title":"Perplexity","description":"Perplexity 웹 검색 프로바이더 설정 (API 키, 검색 모드, 필터링)"},"headers":[],"relativePath":"providers/perplexity-provider.md","filePath":"providers/perplexity-provider.md","lastUpdated":null}'),a={name:"providers/perplexity-provider.md"};function p(c,e,l,i,n,s){return o(),r("div",null,[...e[0]||(e[0]=[d('<h1 id="perplexity-웹-검색-프로바이더" tabindex="-1">Perplexity (웹 검색 프로바이더) <a class="header-anchor" href="#perplexity-웹-검색-프로바이더" aria-label="Permalink to &quot;Perplexity (웹 검색 프로바이더)&quot;">​</a></h1><p>Perplexity 플러그인은 Perplexity Search API 또는 OpenRouter를 통한 Perplexity Sonar를 이용한 웹 검색 기능을 제공합니다.</p><div class="info custom-block"><p class="custom-block-title">NOTE</p><p>이 페이지는 Perplexity <strong>프로바이더</strong> 설정을 다룹니다. Perplexity <strong>도구</strong>(에이전트가 이를 사용하는 방법)에 대해서는 <a href="/openclaw-docs-ko/tools/perplexity-search">Perplexity 도구</a>를 참고하세요.</p></div><table tabindex="0"><thead><tr><th>속성</th><th>값</th></tr></thead><tbody><tr><td>유형</td><td>웹 검색 프로바이더 (모델 프로바이더 아님)</td></tr><tr><td>인증</td><td><code>PERPLEXITY_API_KEY</code> (직접) 또는 <code>OPENROUTER_API_KEY</code> (OpenRouter 경유)</td></tr><tr><td>설정 경로</td><td><code>plugins.entries.perplexity.config.webSearch.apiKey</code></td></tr></tbody></table><h2 id="시작하기" tabindex="-1">시작하기 <a class="header-anchor" href="#시작하기" aria-label="Permalink to &quot;시작하기&quot;">​</a></h2><ol><li><p><strong>API 키 설정</strong></p><p>대화형 웹 검색 설정 플로우를 실행하세요.</p><pre><code>```bash\nopenclaw configure --section web\n```\n\n또는 키를 직접 설정하세요.\n\n```bash\nopenclaw config set plugins.entries.perplexity.config.webSearch.apiKey &quot;pplx-xxxxxxxxxxxx&quot;\n```\n</code></pre></li><li><p><strong>검색 시작</strong></p></li></ol><p>키가 설정되면 에이전트가 자동으로 Perplexity를 웹 검색에 사용합니다. 추가 단계는 필요하지 않습니다.</p><h2 id="검색-모드" tabindex="-1">검색 모드 <a class="header-anchor" href="#검색-모드" aria-label="Permalink to &quot;검색 모드&quot;">​</a></h2><p>플러그인은 API 키 prefix에 따라 전송(transport) 방식을 자동 선택합니다.</p><p><strong>네이티브 Perplexity API (pplx-)</strong></p><p>키가 <code>pplx-</code>로 시작하면, OpenClaw는 네이티브 Perplexity Search API를 사용합니다. 이 전송 방식은 구조화된 결과를 반환하며 도메인, 언어, 날짜 필터를 지원합니다(아래 필터링 옵션 참고).</p><p><strong>OpenRouter / Sonar (sk-or-)</strong></p><p>키가 <code>sk-or-</code>로 시작하면, OpenClaw는 OpenRouter를 통해 Perplexity Sonar 모델로 라우팅합니다. 이 전송 방식은 인용이 포함된 AI 합성 답변을 반환합니다.</p><table tabindex="0"><thead><tr><th>키 prefix</th><th>전송 방식</th><th>기능</th></tr></thead><tbody><tr><td><code>pplx-</code></td><td>네이티브 Perplexity Search API</td><td>구조화된 결과, 도메인/언어/날짜 필터</td></tr><tr><td><code>sk-or-</code></td><td>OpenRouter (Sonar)</td><td>인용이 포함된 AI 합성 답변</td></tr></tbody></table><h2 id="네이티브-api-필터링" tabindex="-1">네이티브 API 필터링 <a class="header-anchor" href="#네이티브-api-필터링" aria-label="Permalink to &quot;네이티브 API 필터링&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">NOTE</p><p>필터링 옵션은 네이티브 Perplexity API(<code>pplx-</code> 키)를 사용할 때만 이용할 수 있습니다. OpenRouter/Sonar 검색은 이러한 파라미터를 지원하지 않습니다.</p></div><p>네이티브 Perplexity API 사용 시 다음 필터를 지원합니다.</p><table tabindex="0"><thead><tr><th>필터</th><th>설명</th><th>예시</th></tr></thead><tbody><tr><td>국가</td><td>2자리 국가 코드</td><td><code>us</code>, <code>de</code>, <code>jp</code></td></tr><tr><td>언어</td><td>ISO 639-1 언어 코드</td><td><code>en</code>, <code>fr</code>, <code>zh</code></td></tr><tr><td>날짜 범위</td><td>최근성 윈도우</td><td><code>day</code>, <code>week</code>, <code>month</code>, <code>year</code></td></tr><tr><td>도메인 필터</td><td>허용/차단 목록 (최대 20 도메인)</td><td><code>example.com</code></td></tr><tr><td>콘텐츠 예산</td><td>응답별 / 페이지별 토큰 제한</td><td><code>max_tokens</code>, <code>max_tokens_per_page</code></td></tr></tbody></table><h2 id="고급-설정" tabindex="-1">고급 설정 <a class="header-anchor" href="#고급-설정" aria-label="Permalink to &quot;고급 설정&quot;">​</a></h2><details class="details custom-block"><summary>데몬 프로세스용 환경 변수</summary><p>OpenClaw Gateway가 데몬(launchd/systemd)으로 실행되는 경우, <code>PERPLEXITY_API_KEY</code>가 해당 프로세스에서 사용 가능하도록 해야 합니다.</p><pre><code>::: warning\n</code></pre><p><code>~/.profile</code>에만 설정된 키는 해당 환경이 명시적으로 가져와지지 않는 한 launchd/systemd 데몬에서 보이지 않습니다. 게이트웨이 프로세스가 키를 읽을 수 있도록 <code>~/.openclaw/.env</code> 또는 <code>env.shellEnv</code>를 통해 키를 설정하세요.</p></details><p>:::</p><details class="details custom-block"><summary>OpenRouter 프록시 설정</summary><p>Perplexity 검색을 OpenRouter를 통해 라우팅하고자 하는 경우, 네이티브 Perplexity 키 대신 <code>OPENROUTER_API_KEY</code>(prefix <code>sk-or-</code>)를 설정하세요. OpenClaw가 prefix를 감지하여 자동으로 Sonar 전송 방식으로 전환합니다.</p><pre><code>::: tip\n</code></pre><p>OpenRouter 전송 방식은 이미 OpenRouter 계정이 있고 여러 프로바이더에 걸쳐 청구를 통합하고자 하는 경우 유용합니다.</p></details><p>:::</p><h2 id="관련-문서" tabindex="-1">관련 문서 <a class="header-anchor" href="#관련-문서" aria-label="Permalink to &quot;관련 문서&quot;">​</a></h2><blockquote><p><strong>Perplexity 검색 도구</strong> <a href="/openclaw-docs-ko/tools/perplexity-search">→</a> 에이전트가 Perplexity 검색을 호출하고 결과를 해석하는 방법.</p></blockquote><blockquote><p><strong>설정 레퍼런스</strong> <a href="/openclaw-docs-ko/gateway/configuration-reference">→</a> 플러그인 엔트리를 포함한 전체 설정 레퍼런스.</p></blockquote>',26)])])}const P=t(a,[["render",p]]);export{x as __pageData,P as default};
